article_css:
/* Auto-generated CSS for Sweet Couscous with Raisins and Almonds */
@import url('https://fonts.googleapis.com/css2?family=Lora:wght@400;600;700&family=Inter:wght@400;500;600&display=swap');

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Inter', sans-serif;
    font-size: 1rem;
    font-weight: 400;
    line-height: 1.7;
    color: #000000;
    background-color: #FFFFFF;
}

.article-container {
    max-width: 800px;
    margin: 0 auto;
    padding: 2rem;
    background-color: #FFFFFF;
}

.article-header.g4-header {
    margin-bottom: 2.5rem;
}
.article-header.g4-header .article-title {
    font-family: 'Lora', serif;
    font-size: 2.5rem;
    font-weight: 700;
    color: #000000;
    margin: 0 0 0.5rem 0;
    padding-bottom: 0.75rem;
    border-bottom: 3px solid #8B5A9B;
    line-height: 1.2;
}
.article-header.g4-header .article-byline-row {
    display: flex;
    flex-wrap: wrap;
    justify-content: space-between;
    align-items: center;
    gap: 0.5rem;
    margin-top: 0.75rem;
}
.article-header.g4-header .byline-left { display: flex; flex-direction: column; gap: 0.15rem; }
.article-header.g4-header .byline-author { font-weight: 600; color: #000000; }
.article-header.g4-header .byline-date { font-size: 0.875rem; color: #333333; }
.article-header.g4-header .byline-disclaimer { font-size: 0.8rem; color: #333333; font-style: italic; margin-top: 0.2rem; }
.article-header.g4-header .byline-right { display: flex; align-items: center; gap: 0.75rem; flex-wrap: wrap; }
.article-header.g4-header .recipe-meta-pills { display: flex; gap: 0.5rem; flex-wrap: wrap; }
.article-header.g4-header .recipe-meta-pills span {
    background: #5A3A6B;
    color: #000000;
    padding: 0.25rem 0.6rem;
    border-radius: 999px;
    font-size: 0.85rem;
}

/* Typography */
h1 {
    font-family: 'Lora', serif;
    font-size: 2.5rem;
    font-weight: 700;
    color: #000000;
    margin-bottom: 1.5rem;
    line-height: 1.2;
}

h2 {
    font-family: 'Lora', serif;
    font-size: 1.875rem;
    font-weight: 700;
    color: #8B5A9B;
    margin-top: 2.5rem;
    margin-bottom: 1rem;
    line-height: 1.3;
}

h3 {
    font-family: 'Inter', sans-serif;
    font-size: 1.5rem;
    font-weight: 600;
    color: #000000;
    margin-top: 1.5rem;
    margin-bottom: 0.75rem;
    line-height: 1.4;
}

p {
    margin-bottom: 1.2rem;
    color: #333333;
}

/* Lists */
.numbered-list {
    list-style: none;
    padding: 0;
    margin: 1rem 0;
}

.numbered-list li {
    display: flex;
    align-items: flex-start;
    margin-bottom: 0.8rem;
    padding-left: 0;
}

.numbered-list .number-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 28px;
    height: 28px;
    background-color: #FF6B35;
    color: #FFFFFF;
    border-radius: 50%;
    font-weight: 600;
    font-size: 0.9rem;
    margin-right: 1rem;
    flex-shrink: 0;
}

.numbered-list .item-content {
    flex: 1;
    padding-top: 0.2rem;
}

.numbered-list .item-title {
    font-weight: 600;
    color: #000000;
}

.bullet-list {
    list-style: none;
    padding-left: 0;
    margin: 1rem 0;
}

.bullet-list li {
    position: relative;
    padding-left: 1.5rem;
    margin-bottom: 0.8rem;
    color: #333333;
}

.bullet-list li::before {
    content: "";
    position: absolute;
    left: 0;
    top: 0.6rem;
    width: 6px;
    height: 6px;
    background-color: #FF6B35;
    border-radius: 50%;
}

/* Images */
.article-image {
    width: 100%;
    height: auto;
    border-radius: 12px;
    margin: 1.5rem 0;
    box-shadow: 0 4px 20px rgba(0,0,0,0.08);
    display: block;
}

/* Pro Tips Box */
.pro-tips-box {
    background-color: #FFF5F0;
    border-left: 4px solid #FF6B35;
    padding: 1.5rem;
    margin: 2rem 0;
    border-radius: 0 12px 12px 0;
}

.pro-tips-box h2 {
    margin-top: 0;
    color: #8B5A9B;
    font-size: 1.5rem;
}

.pro-tips-box .tip-item {
    display: flex;
    align-items: flex-start;
    margin-bottom: 1rem;
}

.pro-tips-box .tip-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 24px;
    height: 24px;
    background-color: #8B5A9B;
    color: white;
    border-radius: 50%;
    font-size: 0.8rem;
    font-weight: 600;
    margin-right: 0.75rem;
    flex-shrink: 0;
}

.pro-tips-box .tip-content {
    flex: 1;
}

.pro-tips-box .tip-title {
    font-weight: 600;
    color: #000000;
    display: inline;
}

/* FAQs */
.faq-section {
    margin: 1.5rem 0;
}

.faq-item {
    margin-bottom: 1.5rem;
}

.faq-question {
    font-weight: 600;
    color: #000000;
    font-size: 1.1rem;
    margin-bottom: 0.5rem;
}

.faq-answer {
    color: #333333;
    padding-left: 0;
}

/* Recipe Card */
.recipe-card {
    background-color: #FFFFFF;
    border: 2px solid #FFE5D9;
    border-radius: 16px;
    padding: 2rem;
    margin-top: 2rem;
    box-shadow: 0 4px 20px rgba(0,0,0,0.08);
}

.recipe-card-header {
    display: flex;
    align-items: center;
    margin-bottom: 1.5rem;
    flex-wrap: wrap;
    gap: 1rem;
}

.recipe-card-image {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #E8D8F0;
}

.recipe-card-title {
    flex: 1;
    min-width: 200px;
}

.recipe-card-title h2 {
    margin: 0;
    font-size: 1.5rem;
    color: #000000;
    font-family: 'Lora', serif;
}

.recipe-card-title p {
    margin: 0.25rem 0 0 0;
    font-size: 0.9rem;
    color: #333333;
}

.recipe-meta {
    display: flex;
    gap: 1.5rem;
    margin: 1rem 0;
    flex-wrap: wrap;
}

.recipe-meta-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    font-size: 0.9rem;
    color: #333333;
}

.recipe-meta-item .icon {
    color: #FF6B35;
    font-size: 1.1rem;
}

.recipe-buttons {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1rem;
    margin: 1.5rem 0;
}

.btn {
    padding: 0.875rem 1.5rem;
    border: none;
    border-radius: 8px;
    font-weight: 600;
    cursor: pointer;
    text-align: center;
    text-decoration: none;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 0.5rem;
    transition: all 0.2s;
    font-family: 'Inter', sans-serif;
    font-size: 0.95rem;
}

.btn-print {
    background-color: #2D2D2D;
    color: white;
}

.btn-print:hover {
    background-color: #000000;
}

.btn-pin {
    background-color: #E60023;
    color: white;
}

.btn-pin:hover {
    background-color: #FF1A3C;
}

.recipe-columns {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 2rem;
    margin-top: 1.5rem;
}

@media (max-width: 600px) {
    .recipe-columns {
        grid-template-columns: 1fr;
    }
}

.recipe-ingredients h3,
.recipe-instructions h3 {
    margin-top: 0;
    margin-bottom: 1rem;
    font-size: 1.2rem;
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.ingredient-checklist {
    list-style: none;
    padding: 0;
}

.ingredient-checklist li {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.5rem 0;
    border-bottom: 1px solid #E8D8F0;
}

.ingredient-checklist li:last-child {
    border-bottom: none;
}

.ingredient-checklist input[type="checkbox"] {
    width: 18px;
    height: 18px;
    accent-color: #8B5A9B;
    cursor: pointer;
}

.instruction-list {
    list-style: none;
    counter-reset: instruction;
    padding: 0;
}

.instruction-list li {
    display: flex;
    gap: 1rem;
    margin-bottom: 1rem;
    align-items: flex-start;
}

.instruction-list li::before {
    counter-increment: instruction;
    content: counter(instruction);
    display: flex;
    align-items: center;
    justify-content: center;
    width: 28px;
    height: 28px;
    background-color: #8B5A9B;
    color: white;
    border-radius: 50%;
    font-weight: 600;
    font-size: 0.85rem;
    flex-shrink: 0;
    margin-top: 0.1rem;
}

.chef-notes {
    background-color: #FFFFFF;
    padding: 1rem;
    border-radius: 8px;
    margin-top: 1.5rem;
    border-left: 4px solid #8B5A9B;
}

.chef-notes h4 {
    margin: 0 0 0.5rem 0;
    color: #000000;
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.chef-notes p {
    margin: 0;
    font-size: 0.95rem;
}

.recipe-footer {
    margin-top: 1.5rem;
    padding-top: 1rem;
    border-top: 1px solid #E8D8F0;
    display: flex;
    justify-content: center;
    gap: 2rem;
    font-size: 0.9rem;
    color: #333333;
}

.recipe-footer strong {
    color: #000000;
}

/* Utility */
.intro-text {
    font-size: 1.05rem;
    line-height: 1.8;
    color: #333333;
    margin-bottom: 2rem;
}
